1030 void VPInstruction::execute(VPTransformState &State) {
1031   assert(!State.Lane && "VPInstruction executing an Lane");
1032   IRBuilderBase::FastMathFlagGuard FMFGuard(State.Builder);
1033   assert(flagsValidForOpcode(getOpcode()) &&
1034          "Set flags not supported for the provided opcode");
1035   if (hasFastMathFlags())
1036     State.Builder.setFastMathFlags(getFastMathFlags());
1037   bool GeneratesPerFirstLaneOnly = canGenerateScalarForFirstLane() &&
1038                                    (vputils::onlyFirstLaneUsed(this) ||
1039                                     isVectorToScalar() || isSingleScalar());
1040   bool GeneratesPerAllLanes = doesGeneratePerAllLanes();
1041   if (GeneratesPerAllLanes) {
1042     for (unsigned Lane = 0, NumLanes = State.VF.getFixedValue();
1043          Lane != NumLanes; ++Lane) {
1044       Value *GeneratedValue = generatePerLane(State, VPLane(Lane));
1045       assert(GeneratedValue && "generatePerLane must produce a value");
1046       State.set(this, GeneratedValue, VPLane(Lane));
1047     }
1048     return;
1049   }
1050 
1051   Value *GeneratedValue = generate(State);
1052   if (!hasResult())
1053     return;
1054   assert(GeneratedValue && "generate must produce a value");
1055   assert((((GeneratedValue->getType()->isVectorTy() ||
1056             GeneratedValue->getType()->isStructTy()) ==
1057            !GeneratesPerFirstLaneOnly) ||
1058           State.VF.isScalar()) &&
1059          "scalar value but not only first lane defined");
1060   State.set(this, GeneratedValue,
1061             /*IsScalar*/ GeneratesPerFirstLaneOnly);
1062 }
